python3 -c "
import json
with open('./search_data_3.json', 'r') as f:
    data = json.load(f)

print('=== Detailed metadata_dimensions Analysis ===')
md = data['metadata_dimensions']
for key in md.keys():
    print(f'{key}: {type(md[key]).__name__}')
    if isinstance(md[key], dict):
        for sub_key in md[key].keys():
            print(f'  - {sub_key}')

print()
print('=== Sample Data Schema Validation ===')
sample_schema = {'text': str, 'label': str, 'topic': str}
label_values = {'OFF', 'NOT'}
schema_valid = True
for i, item in enumerate(data['sample_data']):
    for field, expected_type in sample_schema.items():
        if field not in item:
            print(f'  ✗ Item {i}: Missing field \"{field}\"')
            schema_valid = False
        elif not isinstance(item[field], expected_type):
            print(f'  ✗ Item {i}: Field \"{field}\" has wrong type')
            schema_valid = False
    if item.get('label') not in label_values:
        print(f'  ✗ Item {i}: Invalid label \"{item.get(\"label\")}\"')
        schema_valid = False

if schema_valid:
    print('  ✓ All 20 samples have valid schema')

print()
print('=== Label Distribution Check ===')
labels = [item['label'] for item in data['sample_data']]
print(f'  OFF: {labels.count(\"OFF\")}')
print(f'  NOT: {labels.count(\"NOT\")}')
"

